# 输入获取
arr = input().split(",")


# 算法入口
def getResult(arr):
    count = {}
    first = {}

    for i in range(len(arr)):
        s = arr[i]

        if count.get(s) is None:
            count[s] = 0
        count[s] += 1

        if first.get(s) is None:
            first[s] = i

    tmp = list(first.keys())
    tmp.sort(key=lambda x: (-count[x], first[x]))
    return ",".join(tmp)


# 算法调用
print(getResult(arr))
